function norm(x) {
  if (x === null || x === undefined) return "";
  return String(x).trim();
}

return items.map((item, idx) => {
  const j = item.json;

  j.mock_mailbox = "yann.mastin@gmail.com";
  j.human_validator_email = "yann.mastin@gmail.com";
  j.sender_email = "yann@nomiks.io";

  j.ticket_id = norm(j.ticket_id) || `ticket_${idx + 1}`;
  j.channel = norm(j.channel);
  j.customer_email = norm(j.customer_email) || "unknown_customer@example.com";
  j.subscription_tier = norm(j.subscription_tier);
  j.category = norm(j.category);
  j.subcategory = norm(j.subcategory);
  j.priority = norm(j.priority);
  j.subject = norm(j.subject);
  j.description = norm(j.description);
  j.status = norm(j.status);
  j.tags = norm(j.tags);
  j.escalated_to_product = norm(j.escalated_to_product);

  j.first_response_time_min_num = Number(j.first_response_time_min || j.first_response_time || 0);
  j.resolution_time_hours_num = Number(j.resolution_time_hours || j.resolution_time || 0);
  j.csat_num = (j.csat === "" || j.csat === null || j.csat === undefined) ? null : Number(j.csat);

  j.channel_normalized = j.channel.toLowerCase();
  j.priority_normalized = j.priority.toLowerCase();
  j.status_normalized = j.status.toLowerCase();
  j.subscription_tier_normalized = j.subscription_tier.toLowerCase();

  j.tags_list = j.tags.split(",").map(x => x.trim()).filter(Boolean);

  j.evidence_text = [
    j.ticket_id,
    j.channel,
    j.subscription_tier,
    j.category,
    j.subcategory,
    j.priority,
    j.subject,
    j.description,
    j.status,
    j.tags
  ].join(" | ").toLowerCase();

  return { json: j };
});

return items.map(item => {
  const j = item.json;
  j.workflow_scope = "excluded_non_email";
  j.route_queue = "excluded_from_email_workflow";
