});

const targetSubject = "trade republic connection broken for a month";

if (!items.length) return items;

let chosen = items.find(item => {
  const s = String(item.json.subject || "").trim().toLowerCase();
  return s === targetSubject;
});

if (!chosen) chosen = items[0];

chosen.json.demo_selected = true;
chosen.json.demo_selection_reason = chosen.json.subject
  ? `Selected for single-email GPT demo: ${chosen.json.subject}`
  : "Selected as first available email row for single-email GPT demo.";

return [chosen];

const OPPORTUNITY_RULES = [
  {name: "Account sync reliability", owner: "Engineering + Product", issue_family: "bank_sync_reliability", patterns: [/trade republic/i,/bank[\s_-]?sync/i,/aggregation/i,/aggregator/i,/connect(ion|ed|ing)?\s+bank/i,/account\s+disconnect/i,/missing\s+transaction/i,/balance\s+(wrong|mismatch|incorrect|stale)/i,/reconnect/i,/sync\s+fail/i,/sync\s+issue/i,/account\s+sync/i,/bank\s+connection/i]},
  {name: "Billing and subscription clarity", owner: "Product + Ops", issue_family: "billing_subscription", patterns: [/billing/i,/subscription/i,/charged/i,/charge/i,/refund/i,/cancel/i,/cancellation/i,/invoice/i,/payment\s+method/i,/plan/i,/renewal/i,/trial/i,/pricing/i]},
  {name: "Finary One service delivery and SLA", owner: "Ops + Product", issue_family: "premium_service_sla", patterns: [/finary\s+one/i,/advisor/i,/wealth/i,/premium/i,/appointment/i,/meeting/i,/call\s+back/i,/service\s+delay/i,/sla/i,/onboarding/i,/portfolio\s+review/i,/private\s+client/i]},
  {name: "Product bug stability", owner: "Engineering", issue_family: "product_bug", patterns: [/bug/i,/crash/i,/error/i,/not\s+working/i,/doesn'?t\s+work/i,/broken/i,/freeze/i,/loading/i,/display\s+issue/i,/wrong\s+value/i,/duplicate/i,/issue\s+in\s+app/i,/problem\s+in\s+app/i]}
];
function classify(text) {
  const matches = [];
  for (const rule of OPPORTUNITY_RULES) {
    const hits = rule.patterns.filter(p => p.test(text));
    if (hits.length > 0) matches.push({name: rule.name, owner: rule.owner, issue_family: rule.issue_family, hit_count: hits.length, matched_patterns: hits.map(x => x.toString())});
  }
  if (!matches.length) return {opportunity_name: "Other / uncategorized", issue_family: "uncategorized", owner: "Ops", rule_strength: 0, matched_patterns: []};
  matches.sort((a,b) => b.hit_count - a.hit_count);
  return {opportunity_name: matches[0].name, issue_family: matches[0].issue_family, owner: matches[0].owner, rule_strength: matches[0].hit_count, matched_patterns: matches[0].matched_patterns};
}
return items.map(item => {
  const j = item.json;
  Object.assign(j, classify(j.evidence_text || ""));
  return { json: j };
});

function hasAny(text, patterns) { return patterns.some(p => new RegExp(p, "i").test(text || "")); }

return items.map(item => {
  const j = item.json;
  const text = j.evidence_text || "";
  const premiumTiers = ["plus","premium","gold","finary one","one","pro","private","finary plus"];
  const highPriorities = ["high","urgent","p1","critical"];
  const openStatuses = ["open","pending","waiting","in progress","new"];

  j.is_premium = premiumTiers.includes(j.subscription_tier_normalized || "");
  j.is_high_priority = highPriorities.includes(j.priority_normalized || "");
  j.is_open = openStatuses.includes(j.status_normalized || "");
  j.is_escalated_product = ["true","yes","1","y"].includes(String(j.escalated_to_product || "").toLowerCase());

  let severityProxy = 0;
  if (j.is_high_priority) severityProxy += 2;
  if (j.is_open) severityProxy += 1.5;
  if (j.is_escalated_product) severityProxy += 1.5;
  if (j.csat_num !== null && j.csat_num <= 2) severityProxy += 2;
  else if (j.csat_num === 3) severityProxy += 1;
  if ((j.resolution_time_hours_num || 0) >= 72) severityProxy += 2;
  else if ((j.resolution_time_hours_num || 0) >= 24) severityProxy += 1;
  if ((j.first_response_time_min_num || 0) >= 1440) severityProxy += 2;
  else if ((j.first_response_time_min_num || 0) >= 240) severityProxy += 1;

  let viralityRisk = 0;
  if (hasAny(text, ["scam","unacceptable","ridiculous","angry","furious","terrible","awful","complain","twitter","linkedin","social","public","frustrat","annoy","disappointed","trust","urgent","immediately"])) viralityRisk += 2;
  if (hasAny(text, ["cancel","subscription","paying","value"])) viralityRisk += 1;

  let trustRisk = 0;
  if (hasAny(text, ["money","balance","net worth","portfolio","charged","refund","missing transaction","bank","security","access","hacked"])) trustRisk += 2;

  j.severity_proxy = Number(severityProxy.toFixed(2));
  j.virality_risk = Math.min(viralityRisk, 5);
  j.trust_risk = Math.min(trustRisk, 5);

  return { json: j };
});

const institutionCriticality = {"trade republic": 2, "boursorama": 1, "binance": 2, "coinbase": 2};

function detectInstitution(text) {
  const lower = (text || "").toLowerCase();
  for (const key of Object.keys(institutionCriticality)) if (lower.includes(key)) return key;
  return "";
}

return items.map(item => {
  const j = item.json;
  const inst = detectInstitution(j.evidence_text || "");
  const instScore = inst ? institutionCriticality[inst] : 0;

  j.detected_institution = inst || "not_detected";
  j.ticket_priority_score = Number(((j.rule_strength || 0) * 1.0 + (j.severity_proxy || 0) * 1.5 + (j.is_premium ? 2 : 0) + (j.virality_risk || 0) * 1.0 + (j.trust_risk || 0) * 1.0 + (j.is_escalated_product ? 2 : 0) + ((j.resolution_time_hours_num || 0) >= 24 ? 1 : 0) + ((j.first_response_time_min_num || 0) >= 240 ? 1 : 0) + instScore).toFixed(2));

  const isSyncCritical = j.issue_family === "bank_sync_reliability" && ["trade republic","coinbase","binance"].includes(j.detected_institution);
  const isPremiumCritical = j.is_premium && j.ticket_priority_score >= 7;
  const isProductCritical = j.is_escalated_product || j.ticket_priority_score >= 9;

  if (isSyncCritical || isPremiumCritical || isProductCritical) {
    j.route_queue = "tier_1_internal_priority";
    j.route_owner = j.owner || "Engineering + Product";
    j.sla_target = "same_day";
  } else if (j.ticket_priority_score >= 5) {
    j.route_queue = "tier_2_specialist_queue";
    j.route_owner = j.owner || "Ops";
    j.sla_target = "24h";
  } else {
    j.route_queue = "tier_3_self_serve_or_backlog";
    j.route_owner = "Ops";
    j.sla_target = "72h";
  }

  j.routing_reason = j.route_queue === "tier_1_internal_priority"
    ? "Trust-critical, premium-exposed, institution-critical, or escalated case."
    : j.route_queue === "tier_2_specialist_queue"
      ? "Moderate complexity requiring specialist review."
      : "Low complexity / self-serve or backlog candidate.";

  return { json: j };
});

const KNOWLEDGE_BASE = [
  {kb_id: "KB-001", issue_family: "bank_sync_reliability", institution: "trade republic", known_case: true, approved_product_notes: "Trade Republic sync reliability is treated as a top-priority reliability topic. Acknowledge the issue early, avoid ETAs, and explain that recurring reliability improvements are being prioritized.", approved_customer_guidance: "Apologize first, validate the frustration, state that the issue is top priority, explain that product reliability work is ongoing, and avoid inventing a timeline."},
  {kb_id: "KB-002", issue_family: "billing_subscription", institution: "generic", known_case: true, approved_product_notes: "Billing confusion should be explained clearly and calmly. Focus on clarity, perceived value, and the next step. Avoid defensive language.", approved_customer_guidance: "Acknowledge the confusion, explain the billing event, and reassure without overclaiming."}
];

function matchKB(issueFamily, institution) {
  const direct = KNOWLEDGE_BASE.find(x => x.issue_family === issueFamily && x.institution === institution);
  if (direct) return direct;
  const generic = KNOWLEDGE_BASE.find(x => x.issue_family === issueFamily && x.institution === "generic");
  if (generic) return generic;
  return null;
}

return items.map(item => {
  const j = item.json;
  const institution = j.detected_institution || "generic";
  const kbMatch = matchKB(j.issue_family, institution);

  j.kb_match_found = Boolean(kbMatch);
  j.kb_id = kbMatch ? kbMatch.kb_id : "";
  j.known_case = Boolean(kbMatch && kbMatch.known_case);
  j.approved_product_notes = kbMatch ? kbMatch.approved_product_notes : "No known case found in the internal knowledge base. Keep the reply careful, honest, and focused on the next step.";
  j.approved_customer_guidance = kbMatch ? kbMatch.approved_customer_guidance : "This appears to be a new case. A human validator must review the draft before final delivery.";
  j.validation_required = !j.known_case;

  return { json: j };
});

return items.map(item => {
  const j = item.json;
  j.gpt_prompt = `You are drafting a customer support reply.

Use this structure:
1. apologize first
2. validate the customer’s frustration
3. address the main issue immediately
4. provide product perspective
5. explain what is being done
6. reassure without overpromising
7. connect the issue to broader product reliability when relevant

Constraints:
