return items.map(item => {
  item.json.openai_payload = {
    model: "gpt-4o",
    instructions: "You are a careful customer support drafting assistant. Follow the prompt strictly and return valid JSON only.",
    input: item.json.gpt_prompt,
    text: { format: { type: "json_object" } }
  };
  return item;
});

function safeFallback(j) {
  const subjectPrefix =
    j.route_queue === "tier_1_internal_priority"
      ? "[PRIORITY]"
      : j.route_queue === "tier_2_specialist_queue"
        ? "[SPECIALIST]"
        : "[STANDARD]";

  return {
    reply_subject: `${subjectPrefix} Re: ${j.subject || "Your request"}`,
    reply_body: [
      "Hi,",
      "",
      "First of all, I’m sorry for the experience here.",
      "",
      "I completely understand why this is frustrating.",
      "",
      "We’ve reviewed your case and routed it to the appropriate team based on the issue type and impact.",
      "",
      "We want to be transparent: we’ll keep the case moving, but we do not want to overpromise on timing until we have a confirmed update.",
      "",
      "Thanks again for raising this — your feedback helps us improve both the immediate handling of the issue and the broader product experience behind it.",
      "",
      "Best,",
      "Finary Support"
    ].join("\n"),
    internal_summary: `Fallback draft used. Ticket=${j.ticket_id}. Issue family=${j.issue_family}. Queue=${j.route_queue}.`
  };
}

function extractOpenAIText(j) {
  if (typeof j.output_text === "string" && j.output_text.trim()) return j.output_text;
  const outputs = j.output || [];
  for (const out of outputs) {
    const contents = out.content || [];
    for (const c of contents) {
      if (typeof c.text === "string" && c.text.trim()) return c.text;
    }
  }
  return "";
}

return items.map(item => {
  const j = item.json;
  const rawText = extractOpenAIText(j);

  let parsed = null;
  try {
    if (rawText) parsed = JSON.parse(rawText);
  } catch (e) {}

  const fallback = safeFallback(j);
  const finalDraft = parsed || fallback;

  j.reply_subject = finalDraft.reply_subject || fallback.reply_subject;
  j.reply_body = finalDraft.reply_body || fallback.reply_body;
  j.internal_summary = finalDraft.internal_summary || fallback.internal_summary;

  j.validator_email_body = [
    "Please review the customer draft below before final delivery.",
    "",
    `Ticket ID: ${j.ticket_id || 'N/A'}`,
    `Customer: ${j.customer_email || 'N/A'}`,
    `Issue family: ${j.issue_family || 'N/A'}`,
    `Route: ${j.route_queue || 'N/A'}`,
    `Known case: ${j.known_case || false}`,
    "",
    "--- EMAIL TO CUSTOMER ---",
    "",
    `Subject: ${j.reply_subject}`,
    "",
    `${j.reply_body}`,
    "",
    "--- END ---",
    "",
    "Decision expected: APPROVE or REVISE."
  ].join("\n");

  return { json: j };
});

return items.map(item => ({
  json: {
    ticket_id: item.json.ticket_id,
