return items.map(item => {
  const j = item.json;
  j.audit = {
    workflow_scope: "email_only_single_demo",
    demo_selected: j.demo_selected || false,
    demo_selection_reason: j.demo_selection_reason || "",
    issue_family: j.issue_family,
