    customer_email_original: j.customer_email,
    mock_recipient_email: "yann.mastin@gmail.com",
    validator_email: "yann.mastin@gmail.com"
  };
  return { json: j };
});

const rows = items.map(i => i.json);
const processed = rows.filter(x => x.workflow_scope !== "excluded_non_email");
const excluded = rows.filter(x => x.workflow_scope === "excluded_non_email");
const htmlDashboard = `
  <html>
    <body style="font-family: Arial, sans-serif; padding: 16px;">
      <h2>Single Email Demo Summary</h2>
      <div style="display:flex; gap:16px; margin-bottom:16px;">
        <div style="padding:12px; border:1px solid #ddd; border-radius:8px;"><strong>Processed email rows</strong><br/>${processed.length}</div>
        <div style="padding:12px; border:1px solid #ddd; border-radius:8px;"><strong>Excluded rows</strong><br/>${excluded.length}</div>
      </div>
      <h3>Selected ticket</h3>
      <pre>${JSON.stringify(processed[0] ? {
        ticket_id: processed[0].ticket_id,
        subject: processed[0].subject,
        issue_family: processed[0].issue_family,
        score: processed[0].ticket_priority_score,
        route_queue: processed[0].route_queue,
        known_case: processed[0].known_case,
        validation_required: processed[0].validation_required,
        delivery_status: processed[0].mock_delivery_status,
        reply_subject: processed[0].reply_subject,
        reply_body: processed[0].reply_body
      } : {}, null, 2)}</pre>
    </body>
  </html>
`;
return [{
  json: {
    workflow_name: "Finary - Single Email Demo + KB + GPT + Merge + Full Email Content v7",
    upload_instructions: {
      endpoint_path: "/webhook/finary-single-email-demo-gpt-merge-v7",
      expected_binary_field: "data",
      upload_method: "Send the Excel file as multipart/form-data with the file field named data."
    },
    notes: {
      select_openai_credential_in_gpt_node: true,
      select_email_credential_in_all_3_email_nodes: true,
      validator_receives_exact_client_draft_first: true,
      after_approval_same_draft_is_sent_to_client: true
    },
    selected_email_result: processed[0] || {},
    visual_outputs: { html_dashboard: htmlDashboard },
    excluded_rows_count: excluded.length
  }
}];
